<?php
session_start();
if (!is_dir(__DIR__ . '/data')) mkdir(__DIR__ . '/data', 0775, true);
$pdo = new PDO('sqlite:' . __DIR__ . '/data/devoto.sqlite');
$pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
$pdo->exec("CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE, password_hash TEXT, display_name TEXT, created_at TEXT, updated_at TEXT)");
$pdo->exec("CREATE TABLE IF NOT EXISTS dogs (id INTEGER PRIMARY KEY AUTOINCREMENT, nombre TEXT, dueno TEXT, telefono TEXT, telefono_alt TEXT, prioridad_contacto TEXT, vacunas TEXT, salud TEXT, comida TEXT, zonas_json TEXT, precios_json TEXT, created_at TEXT, updated_at TEXT)");
$pdo->exec("CREATE TABLE IF NOT EXISTS jobs (id INTEGER PRIMARY KEY AUTOINCREMENT, dog_id INTEGER, fecha_iso TEXT, servicio TEXT, zona TEXT, horas INTEGER, dias INTEGER, tipo_pago TEXT, tarifa_unitaria REAL, descuento_pct REAL, total REAL, estado_cobro TEXT DEFAULT 'pendiente', notes TEXT, detalle_json TEXT, created_at TEXT, paid_at TEXT)");
$pdo->exec("CREATE TABLE IF NOT EXISTS reminders (id INTEGER PRIMARY KEY AUTOINCREMENT, dog_id INTEGER, due_at_iso TEXT, message TEXT, status TEXT, created_at TEXT, done_at TEXT)");
$pdo->exec("CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY, value TEXT)");
$usersCount=(int)$pdo->query('SELECT COUNT(*) FROM users')->fetchColumn();
$dogsCount=(int)$pdo->query('SELECT COUNT(*) FROM dogs')->fetchColumn();
if($dogsCount===0){
  $nowDefault=gmdate('c');
  $preciosDefault=json_encode(['hora'=>'9000','combos'=>'','mensual'=>'','personalizado'=>''],JSON_UNESCAPED_UNICODE);
  $pdo->prepare('INSERT INTO dogs(nombre,dueno,telefono,telefono_alt,prioridad_contacto,vacunas,salud,comida,zonas_json,precios_json,raza,raza_otra,foto_url,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)')
      ->execute(['Mancha','Fernando','Sin teléfono','','Primero dueño/a','No informado','Sin notas','Sin indicaciones','[]',$preciosDefault,'Otro','','',$nowDefault,$nowDefault]);
}

function out($p,$s=200){http_response_code($s);header('Content-Type: application/json; charset=utf-8');echo json_encode($p,JSON_UNESCAPED_UNICODE);exit;}
function in(){ $d=json_decode(file_get_contents('php://input')?:'[]',true); return is_array($d)?$d:[]; }
function txt($arr,$k,$max=250,$req=false){$v=trim((string)($arr[$k]??''));$v=preg_replace('/\s+/',' ',$v);if($req&&$v==='')throw new InvalidArgumentException("Falta completar {$k}.");if(mb_strlen($v)>$max)throw new InvalidArgumentException("{$k} es demasiado largo.");return $v;}
function currentUser($pdo){ if(empty($_SESSION['uid'])) return null; $st=$pdo->prepare('SELECT id,username,display_name,created_at,updated_at FROM users WHERE id=?');$st->execute([(int)$_SESSION['uid']]);$u=$st->fetch(PDO::FETCH_ASSOC); if(!$u){unset($_SESSION['uid']);return null;} return $u; }
$cols=$pdo->query("PRAGMA table_info(dogs)")->fetchAll(PDO::FETCH_ASSOC);
$names=array_map(fn($c)=>$c['name'],$cols);
if(!in_array('telefono_alt',$names,true))$pdo->exec("ALTER TABLE dogs ADD COLUMN telefono_alt TEXT DEFAULT ''");
if(!in_array('prioridad_contacto',$names,true))$pdo->exec("ALTER TABLE dogs ADD COLUMN prioridad_contacto TEXT DEFAULT 'Primero dueño/a'");
if(!in_array('precios_json',$names,true))$pdo->exec("ALTER TABLE dogs ADD COLUMN precios_json TEXT DEFAULT '{}'");
if(!in_array('raza',$names,true))$pdo->exec("ALTER TABLE dogs ADD COLUMN raza TEXT DEFAULT 'Otro'");
if(!in_array('raza_otra',$names,true))$pdo->exec("ALTER TABLE dogs ADD COLUMN raza_otra TEXT DEFAULT ''");
if(!in_array('foto_url',$names,true))$pdo->exec("ALTER TABLE dogs ADD COLUMN foto_url TEXT DEFAULT ''");
$jobCols=$pdo->query("PRAGMA table_info(jobs)")->fetchAll(PDO::FETCH_ASSOC);
$jobNames=array_map(fn($c)=>$c['name'],$jobCols);
if(!in_array('detalle_json',$jobNames,true))$pdo->exec("ALTER TABLE jobs ADD COLUMN detalle_json TEXT DEFAULT '{}'");
if(!in_array('dias',$jobNames,true))$pdo->exec("ALTER TABLE jobs ADD COLUMN dias INTEGER DEFAULT 1");
if(!in_array('estado_cobro',$jobNames,true))$pdo->exec("ALTER TABLE jobs ADD COLUMN estado_cobro TEXT DEFAULT 'pendiente'");
if(!in_array('paid_at',$jobNames,true))$pdo->exec("ALTER TABLE jobs ADD COLUMN paid_at TEXT DEFAULT NULL");

if (isset($_GET['api'])) {
  try {
    $api=$_GET['api'];$d=in();$now=gmdate('c');
    if($api==='profile.get'){ $u=currentUser($pdo); if(!$u) out(['ok'=>false,'message'=>'Sesión no iniciada.'],401); out(['ok'=>true,'user'=>$u]); }
    if($api==='logout'){ $_SESSION=[]; if(session_status()===PHP_SESSION_ACTIVE) session_destroy(); out(['ok'=>true,'message'=>'Sesión cerrada correctamente.']); }
    if($api==='login'){ $u=txt($d,'username',60,true);$p=(string)($d['password']??'');$st=$pdo->prepare('SELECT id,username,password_hash,display_name,created_at,updated_at FROM users WHERE username=?');$st->execute([$u]);$row=$st->fetch(PDO::FETCH_ASSOC); if(!$row||!password_verify($p,$row['password_hash'])) out(['ok'=>false,'message'=>'Usuario o contraseña incorrectos.'],401); $_SESSION['uid']=(int)$row['id']; unset($row['password_hash']); out(['ok'=>true,'user'=>$row,'message'=>'Ingreso correcto.']); }
    if(!in_array($api,['bootstrap-admin','login','setup.status'],true) && !currentUser($pdo)) out(['ok'=>false,'message'=>'Debés iniciar sesión para continuar.'],401);
    if($api==='dogs.list'){ $rows=$pdo->query('SELECT * FROM dogs ORDER BY nombre')->fetchAll(PDO::FETCH_ASSOC); foreach($rows as &$r){$r['zonas']=json_decode($r['zonas_json']?:'[]',true)?:[];} out(['ok'=>true,'dogs'=>$rows]); }
    if($api==='dogs.create'){ $st=$pdo->prepare('INSERT INTO dogs(nombre,dueno,telefono,telefono_alt,prioridad_contacto,vacunas,salud,comida,zonas_json,precios_json,raza,raza_otra,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)');$st->execute([txt($d,'nombre',80,true),txt($d,'dueno',120,true),txt($d,'telefono',40)?:'Sin teléfono',txt($d,'telefono_alt',40),txt($d,'prioridad_contacto',60)?:'Primero dueño/a',txt($d,'vacunas',120)?:'No informado',txt($d,'salud',500)?:'Sin notas',txt($d,'comida',500)?:'Sin indicaciones','[]',json_encode(['hora'=>txt($d,'precio_hora',20),'combos'=>txt($d,'precio_combos',120),'mensual'=>txt($d,'precio_mensual',120),'personalizado'=>txt($d,'precio_personalizado',250)],JSON_UNESCAPED_UNICODE),txt($d,'raza',80)?:'Otro',txt($d,'raza_otra',120),txt($d,'foto_url',500),$now,$now]); out(['ok'=>true,'message'=>'Perro guardado correctamente.']); }
    if($api==='dogs.update'){ $id=(int)($d['id']??0); if($id<1) throw new InvalidArgumentException('ID inválido.'); $pdo->prepare('UPDATE dogs SET nombre=?,dueno=?,telefono=?,telefono_alt=?,prioridad_contacto=?,vacunas=?,salud=?,comida=?,precios_json=?,raza=?,raza_otra=?,foto_url=?,updated_at=? WHERE id=?')->execute([txt($d,'nombre',80,true),txt($d,'dueno',120,true),txt($d,'telefono',40),txt($d,'telefono_alt',40),txt($d,'prioridad_contacto',60),txt($d,'vacunas',120),txt($d,'salud',500),txt($d,'comida',500),json_encode(['hora'=>txt($d,'precio_hora',20),'combos'=>txt($d,'precio_combos',120),'mensual'=>txt($d,'precio_mensual',120),'personalizado'=>txt($d,'precio_personalizado',250)],JSON_UNESCAPED_UNICODE),txt($d,'raza',80),txt($d,'raza_otra',120),txt($d,'foto_url',500),$now,$id]); out(['ok'=>true,'message'=>'Ficha actualizada.']); }
    if($api==='dogs.delete'){ $id=(int)($d['id']??0); $pdo->prepare('DELETE FROM jobs WHERE dog_id=?')->execute([$id]); $pdo->prepare('DELETE FROM reminders WHERE dog_id=?')->execute([$id]); $pdo->prepare('DELETE FROM dogs WHERE id=?')->execute([$id]); out(['ok'=>true,'message'=>'Ficha borrada correctamente.']); }
    if($api==='jobs.create'){ $dog=(int)($d['dog_id']??0);$h=max(1,(int)($d['horas']??1));$dias=max(1,(int)($d['dias']??1));$tar=(float)($d['tarifa_unitaria']??9000);$des=(float)($d['descuento_pct']??0);$totCalculado=max(0,($h*$tar)-($h*$tar*$des));$tot=(float)($d['total']??$totCalculado); if($tot<=0) throw new InvalidArgumentException('El total debe ser un número positivo.');$detalle=$d['detalle']??[]; if(!is_array($detalle))$detalle=[]; $dogIds=array_values(array_filter(array_map('intval',$d['dog_ids']??[$dog]),fn($x)=>$x>0)); if(!$dogIds&&$dog>0)$dogIds=[$dog]; $principalDog=$dogIds[0]??$dog; $pdo->prepare('INSERT INTO jobs(dog_id,fecha_iso,servicio,zona,horas,dias,tipo_pago,tarifa_unitaria,descuento_pct,total,estado_cobro,notes,detalle_json,created_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute([$principalDog,$now,txt($d,'servicio',30,true),txt($d,'zona',100,true),$h,$dias,txt($d,'tipo_pago',40,true),$tar,$des,$tot,'pendiente',txt($d,'notes',500),json_encode(['dog_ids'=>$dogIds,'detalle'=>$detalle],JSON_UNESCAPED_UNICODE),$now]);out(['ok'=>true,'total'=>$tot,'message'=>'Trabajo guardado.']); }
    if($api==='jobs.list'){ $rows=$pdo->query('SELECT j.*, d.nombre dog_nombre, d.dueno dog_dueno FROM jobs j JOIN dogs d ON d.id=j.dog_id ORDER BY j.fecha_iso DESC')->fetchAll(PDO::FETCH_ASSOC); out(['ok'=>true,'jobs'=>$rows]); }
    if($api==='jobs.pay'){ $id=(int)($d['id']??0); $pdo->prepare('UPDATE jobs SET estado_cobro=?, paid_at=? WHERE id=?')->execute(['cobrado',$now,$id]); out(['ok'=>true,'message'=>'Marcado como cobrado.']); }
    if($api==='reminders.create'){ $pdo->prepare('INSERT INTO reminders(dog_id,due_at_iso,message,status,created_at) VALUES(?,?,?,?,?)')->execute([(int)($d['dog_id']??0),txt($d,'due_at_iso',40,true),txt($d,'message',400,true),'pending',$now]); out(['ok'=>true,'message'=>'Recordatorio creado.']); }
    if($api==='reminders.list'){ out(['ok'=>true,'reminders'=>$pdo->query('SELECT * FROM reminders ORDER BY due_at_iso')->fetchAll(PDO::FETCH_ASSOC)]); }
    if($api==='reminders.done'){ $pdo->prepare('UPDATE reminders SET status=?, done_at=? WHERE id=?')->execute(['done',$now,(int)($d['id']??0)]); out(['ok'=>true,'message'=>'Recordatorio marcado como hecho.']); }
    if($api==='setup.status'){ $count=(int)$pdo->query('SELECT COUNT(*) FROM users')->fetchColumn(); out(['ok'=>true,'needs_bootstrap'=>$count===0]); }
    if($api==='bootstrap-admin'){ $exists=(int)$pdo->query('SELECT COUNT(*) FROM users')->fetchColumn(); if($exists>0) out(['ok'=>false,'message'=>'La instalación ya fue configurada.'],400); $username=txt($d,'username',60,true); $password=(string)($d['password']??''); $password2=(string)($d['password_repeat']??''); $displayName=txt($d,'display_name',120,true); if(strlen($password)<6) out(['ok'=>false,'message'=>'La contraseña debe tener al menos 6 caracteres.'],422); if($password!==$password2) out(['ok'=>false,'message'=>'Las contraseñas no coinciden.'],422); try{$pdo->prepare('INSERT INTO users(username,password_hash,display_name,created_at,updated_at) VALUES(?,?,?,?,?)')->execute([$username,password_hash($password,PASSWORD_DEFAULT),$displayName,$now,$now]);}catch(PDOException $ex){ if(str_contains(strtolower($ex->getMessage()),'unique')) out(['ok'=>false,'message'=>'Ese usuario ya existe. Elegí otro.'],422); throw $ex;} $_SESSION['uid']=(int)$pdo->lastInsertId(); out(['ok'=>true,'message'=>'Administrador creado correctamente.']); }
    if($api==='profile.update'){ $u=currentUser($pdo); if(!$u) out(['ok'=>false,'message'=>'Sesión no iniciada.'],401); $username=txt($d,'username',60,true); $currentPassword=(string)($d['current_password']??''); $newPassword=(string)($d['new_password']??''); $confirmPassword=(string)($d['confirm_password']??''); $st=$pdo->prepare('SELECT password_hash FROM users WHERE id=?'); $st->execute([(int)$u['id']]); $row=$st->fetch(PDO::FETCH_ASSOC); if($currentPassword!=='' && (!$row || !password_verify($currentPassword,$row['password_hash']))) out(['ok'=>false,'message'=>'La contraseña actual no coincide.'],422); if($newPassword!=='' && strlen($newPassword)<6) out(['ok'=>false,'message'=>'La nueva contraseña debe tener al menos 6 caracteres.'],422); if($newPassword!=='' && $newPassword!==$confirmPassword) out(['ok'=>false,'message'=>'La confirmación de contraseña no coincide.'],422); $hashToSave=$row['password_hash']??''; if($newPassword!=='') $hashToSave=password_hash($newPassword,PASSWORD_DEFAULT); try{$pdo->prepare('UPDATE users SET username=?, password_hash=?, updated_at=? WHERE id=?')->execute([$username,$hashToSave,$now,(int)$u['id']]);}catch(PDOException $ex){ if(str_contains(strtolower($ex->getMessage()),'unique')) out(['ok'=>false,'message'=>'Ese usuario ya existe. Elegí otro.'],422); throw $ex;} out(['ok'=>true,'message'=>'Guardado con éxito.']); }
    out(['ok'=>false,'message'=>'Ruta no encontrada.'],404);
  } catch (InvalidArgumentException $e) { out(['ok'=>false,'message'=>$e->getMessage()],422); }
    catch (Throwable $e) { out(['ok'=>false,'message'=>'Ocurrió un error inesperado.'],500); }
}
?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Paseos y Guardería Devoto</title><script src="https://cdn.tailwindcss.com"></script><style>body{font-family:'Segoe UI',Roboto,Helvetica,Arial,sans-serif;background-color:#f3f4f6;color:#111827;-webkit-tap-highlight-color:transparent}button,select,input,textarea{transition:all .2s ease-in-out}button:active{transform:scale(.98)}.no-scrollbar::-webkit-scrollbar{display:none}.no-scrollbar{-ms-overflow-style:none;scrollbar-width:none}.card{background-color:white;border-radius:1rem;box-shadow:0 4px 6px -1px rgba(0,0,0,.1),0 2px 4px -1px rgba(0,0,0,.06);padding:1.5rem;margin-bottom:1rem;border:2px solid #e5e7eb}.input-grande{width:100%;font-size:1.25rem;padding:1rem;border:2px solid #9ca3af;border-radius:.75rem;margin-top:.5rem;margin-bottom:1.5rem;background-color:white}.input-grande:focus{outline:none;border-color:#2563eb;box-shadow:0 0 0 3px rgba(37,99,235,.3)}.etiqueta{font-size:1.25rem;font-weight:600;color:#374151;display:block}</style></head>
<body class="flex flex-col h-screen overflow-hidden"><header class="bg-blue-700 text-white p-4 shadow-md z-10"><h1 class="text-3xl font-bold text-center tracking-wide">🐕 Paseos Devoto</h1></header><main id="app-content" class="flex-1 overflow-y-auto p-4 pb-28 no-scrollbar bg-gray-100"></main><nav class="bg-white border-t-4 border-gray-200 fixed bottom-0 w-full flex justify-around p-2 z-10 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]"><button onclick="navegar('inicio')" class="nav-btn flex flex-col items-center p-2 rounded-xl text-gray-500 w-1/5" id="nav-inicio"><span class="text-4xl mb-1">🏠</span><span class="text-sm font-bold">Inicio</span></button><button onclick="navegar('perros')" class="nav-btn flex flex-col items-center p-2 rounded-xl text-gray-500 w-1/5" id="nav-perros"><span class="text-4xl mb-1">🐾</span><span class="text-sm font-bold">Perros</span></button><button onclick="navegar('recordatorios')" class="nav-btn flex flex-col items-center p-2 rounded-xl text-gray-500 w-1/5" id="nav-recordatorios"><span class="text-4xl mb-1">⏰</span><span class="text-sm font-bold">Recordar</span></button><button onclick="navegar('paseo')" class="nav-btn flex flex-col items-center p-2 rounded-xl text-gray-500 w-1/5" id="nav-paseo"><span class="text-4xl mb-1">📝</span><span class="text-sm font-bold">Anotar</span></button><button onclick="navegar('cuentas')" class="nav-btn flex flex-col items-center p-2 rounded-xl text-gray-500 w-1/5" id="nav-cuentas"><span class="text-4xl mb-1">💰</span><span class="text-sm font-bold">Plata</span></button></nav><div id="notificacion" class="fixed top-20 left-1/2 transform -translate-x-1/2 bg-green-600 text-white text-2xl font-bold px-6 py-4 rounded-2xl shadow-xl hidden z-50 text-center w-11/12 max-w-md">Mensaje</div>
<script>
const TARIFA_HORA=9000,DESCUENTO_MENSUAL=.2,FACTOR_MENSUAL_DEFAULT=4,COMBO_MULTIPERRO=false,DESCUENTO_COMBO=.1; const NEEDS_BOOTSTRAP=<?= $usersCount===0 ? 'true' : 'false' ?>; const REMINDER_TEMPLATES=['Confirmar paseo','Recordar pago','Actualizar estado del perro'];
const RAZAS_POPULARES=[
{name:'Caniche Toy',size:'Chico',img:'https://images.dog.ceo/breeds/poodle-toy/n02113624_9550.jpg'},
{name:'Chihuahua',size:'Chico',img:'https://images.dog.ceo/breeds/chihuahua/n02085620_1752.jpg'},
{name:'Shih Tzu',size:'Chico',img:'https://images.dog.ceo/breeds/shihtzu/n02086240_4606.jpg'},
{name:'Pug',size:'Chico',img:'https://images.dog.ceo/breeds/pug/n02110958_10307.jpg'},
{name:'Schnauzer Miniatura',size:'Chico',img:'https://images.dog.ceo/breeds/schnauzer-miniature/n02097047_1534.jpg'},
{name:'Beagle',size:'Mediano',img:'https://images.dog.ceo/breeds/beagle/n02088364_11136.jpg'},
{name:'Cocker Spaniel',size:'Mediano',img:'https://images.dog.ceo/breeds/spaniel-cocker/n02102318_3843.jpg'},
{name:'Border Collie',size:'Mediano',img:'https://images.dog.ceo/breeds/collie-border/n02106166_3555.jpg'},
{name:'Bulldog Francés',size:'Mediano',img:'https://images.dog.ceo/breeds/bulldog-french/n02108915_5306.jpg'},
{name:'Otro',size:'Otro',img:'https://images.dog.ceo/breeds/mix/Max_D11.jpg'}
];
let appData={perros:[],registros:[],reminders:[]},currentUser=null;
const api=async (a,b={})=>{const r=await fetch(`?api=${encodeURIComponent(a)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(b)});const j=await r.json();if(!j.ok)throw new Error(j.message||'Error');return j;};
async function cargarDatos(){const [d,j,r]=await Promise.all([api('dogs.list'),api('jobs.list'),api('reminders.list')]);appData.perros=d.dogs;appData.registros=j.jobs.map(x=>({id:+x.id,perroId:+x.dog_id,fecha:x.fecha_iso,servicio:x.servicio,zona:x.zona,horas:+x.horas,total:+x.total,tipoPago:x.tipo_pago,dias:+(x.dias||1),estadoCobro:x.estado_cobro||'pendiente'}));appData.reminders=r.reminders.map(x=>({id:+x.id,dogId:+x.dog_id,dueAt:x.due_at_iso,message:x.message,status:x.status,doneAt:x.done_at}));}
function mostrarMensaje(t,e=false){const n=document.getElementById('notificacion');n.textContent=t;n.className=`fixed top-20 left-1/2 transform -translate-x-1/2 text-white text-2xl font-bold px-6 py-4 rounded-2xl shadow-xl z-50 text-center w-11/12 max-w-md transition-opacity ${e?'bg-red-600':'bg-green-600'}`;n.style.display='block';setTimeout(()=>n.style.display='none',3000)}
function setNav(v){document.querySelector('nav').style.display=v?'flex':'none';}
function navegar(p,param=null){document.querySelectorAll('.nav-btn').forEach(b=>{b.classList.remove('text-blue-700','bg-blue-50');b.classList.add('text-gray-500')});const btn=document.getElementById(`nav-${p}`);if(btn){btn.classList.remove('text-gray-500');btn.classList.add('text-blue-700','bg-blue-50')}const m=document.getElementById('app-content');m.innerHTML='';if(p==='inicio')renderInicio(m);if(p==='perros')renderListaPerros(m);if(p==='perfil')renderPerfil(m);if(p==='nuevo-perro')renderFormularioPerro(m);if(p==='ficha-perro')renderFichaPerro(m,param);if(p==='recordatorios')renderRecordatorios(m);if(p==='paseo')renderAnotarPaseo(m);if(p==='cuentas')renderCuentas(m)}
function renderLogin(c){setNav(false);c.innerHTML=`<h2 class='text-3xl font-bold mb-6 text-center'>Ingresá para continuar</h2><div class='card'><label class='etiqueta'>Usuario:</label><input id='login-user' class='input-grande'><label class='etiqueta'>Contraseña:</label><input id='login-pass' type='password' class='input-grande'><button onclick='hacerLogin()' class='w-full bg-blue-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-blue-800 mt-2'>🔐 Ingresar</button></div>`;actualizarMiniaturaRaza();}
function renderBootstrap(c){setNav(false);c.innerHTML=`<h2 class='text-3xl font-bold mb-6 text-center'>Configurar administrador</h2><div class='card'><label class='etiqueta'>Usuario:</label><input id='boot-user' class='input-grande'><label class='etiqueta'>Contraseña:</label><input id='boot-pass' type='password' class='input-grande'><label class='etiqueta'>Repetir contraseña:</label><input id='boot-pass2' type='password' class='input-grande'><label class='etiqueta'>Nombre visible:</label><input id='boot-name' class='input-grande'><button onclick='crearAdminInicial()' class='w-full bg-blue-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-blue-800 mt-2'>🚀 Crear administrador</button></div>`;actualizarMiniaturaRaza();}
async function crearAdminInicial(){try{await api('bootstrap-admin',{username:document.getElementById('boot-user').value,password:document.getElementById('boot-pass').value,password_repeat:document.getElementById('boot-pass2').value,display_name:document.getElementById('boot-name').value});const p=await api('profile.get');currentUser=p.user;setNav(true);await cargarDatos();mostrarMensaje('Administrador creado correctamente.');navegar('inicio')}catch(e){mostrarMensaje(e.message,true)}}
async function hacerLogin(){try{const r=await api('login',{username:document.getElementById('login-user').value,password:document.getElementById('login-pass').value});currentUser=r.user;setNav(true);await cargarDatos();mostrarMensaje('Ingreso correcto.');navegar('inicio')}catch(e){mostrarMensaje(e.message,true)}}
async function cerrarSesion(){try{await api('logout');currentUser=null;renderLogin(document.getElementById('app-content'));mostrarMensaje('Sesión cerrada correctamente.')}catch(e){mostrarMensaje(e.message,true)}}
function renderInicio(c){const hoy=new Date().toLocaleDateString('es-AR');const p=appData.registros.filter(r=>new Date(r.fecha).toLocaleDateString('es-AR')===hoy).length;const pendientesHoy=appData.reminders.filter(r=>r.status==='pending'&&new Date(r.dueAt).toLocaleDateString('es-AR')===hoy);const listaPendientes=pendientesHoy.length?pendientesHoy.map(r=>{const perro=appData.perros.find(x=>x.id===r.dogId);return `<li class='text-lg mb-2'>• <b>${new Date(r.dueAt).toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'})}</b> - ${perro?.nombre||'Sin perro'}: ${r.message}</li>`}).join(''):"<p class='text-lg text-green-900 font-semibold'>No hay recordatorios pendientes para hoy 🎉</p>";c.innerHTML=`<h2 class='text-3xl font-bold mb-6 text-center'>¡Hola! ¿Cómo estás hoy?</h2><div class='card text-center bg-blue-50 border-blue-200'><p class='text-xl text-gray-700'>Hoy es:</p><p class='text-3xl font-bold text-blue-800'>${hoy}</p></div><div class='card bg-yellow-50 border-yellow-300'><div class='flex items-center justify-between'><h3 class='text-2xl font-black text-yellow-800'>⏰ Pendientes de hoy</h3><span class='text-3xl font-black text-yellow-700'>${pendientesHoy.length}</span></div><div class='mt-3'>${pendientesHoy.length?`<ul>${listaPendientes}</ul>`:listaPendientes}</div><button onclick="navegar('recordatorios')" class='mt-4 w-full bg-yellow-500 text-white text-2xl font-bold py-4 rounded-2xl border-b-4 border-yellow-700'>Ver recordatorios</button></div>${renderAgendaInicio()}<div class='grid grid-cols-2 gap-4 mt-6'><div class='card text-center flex flex-col justify-center cursor-pointer' onclick="navegar('perros')"><span class='text-5xl mb-2'>🐾</span><span class='text-4xl font-bold text-blue-700'>${appData.perros.length}</span><span class='text-xl text-gray-600 font-semibold'>Perros en total</span></div><div class='card text-center flex flex-col justify-center cursor-pointer' onclick="navegar('cuentas')"><span class='text-5xl mb-2'>🚶‍♂️</span><span class='text-4xl font-bold text-green-600'>${p}</span><span class='text-xl text-gray-600 font-semibold'>Trabajos Hoy</span></div></div><button onclick="navegar('perfil')" class='mt-6 w-full bg-indigo-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-indigo-800'>👤 Perfil</button><button onclick="navegar('paseo')" class='mt-4 w-full bg-green-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-green-800 flex justify-center items-center gap-4'><span>📝</span> ¡Anotar un trabajo nuevo!</button>`}
function sugerirMensajeRecordatorio(){const sel=document.getElementById('rem-template');const msg=document.getElementById('rem-message');if(!sel||!msg)return;msg.value=sel.value||'';}
async function guardarRecordatorio(){try{const perroId=parseInt(document.getElementById('rem-dog').value);const fecha=document.getElementById('rem-date').value;const hora=document.getElementById('rem-time').value;const message=document.getElementById('rem-message').value;await api('reminders.create',{dog_id:perroId,due_at_iso:new Date(`${fecha}T${hora}:00`).toISOString(),message});await cargarDatos();mostrarMensaje('Recordatorio creado.');navegar('recordatorios');}catch(e){mostrarMensaje(e.message,true)}}
async function marcarRecordatorioDone(id){try{await api('reminders.done',{id});await cargarDatos();mostrarMensaje('Recordatorio marcado como enviado.');navegar('recordatorios');}catch(e){mostrarMensaje(e.message,true)}}
function renderRecordatorios(c){if(!appData.perros.length){c.innerHTML=`<h2 class='text-3xl font-bold mb-6'>Recordatorios</h2><div class='card text-center'><p class='text-2xl mb-4'>Primero tenés que anotar un perro en el sistema.</p><button onclick="navegar('nuevo-perro')" class='bg-blue-600 text-white text-2xl font-bold py-4 px-6 rounded-xl w-full'>Ir a crear perro</button></div>`;return;}const opts=appData.perros.map(p=>`<option value='${p.id}'>${p.nombre} (de ${p.dueno})</option>`).join('');const pendientes=appData.reminders.filter(r=>r.status==='pending').sort((a,b)=>a.dueAt.localeCompare(b.dueAt));const lista=pendientes.length?pendientes.map(r=>{const perro=appData.perros.find(p=>p.id===r.dogId);return `<div class='card border-yellow-300'><p class='text-xl font-bold'>${perro?.nombre||'Sin perro'} - ${new Date(r.dueAt).toLocaleString('es-AR')}</p><p class='text-lg my-2'>${r.message}</p><button onclick='marcarRecordatorioDone(${r.id})' class='w-full bg-green-600 text-white text-2xl font-bold py-4 rounded-xl border-b-4 border-green-800'>✅ Marcar como enviado</button></div>`;actualizarMiniaturaRaza();}).join(''):`<div class='card text-center text-xl text-gray-500'>No hay recordatorios pendientes.</div>`;const ahora=new Date();const fechaBase=ahora.toISOString().slice(0,10);const horaBase=ahora.toTimeString().slice(0,5);const quickButtons=REMINDER_TEMPLATES.map(t=>`<button onclick="document.getElementById('rem-message').value='${t}'" class='bg-purple-100 border-2 border-purple-300 text-purple-800 text-xl font-bold py-3 px-4 rounded-xl'>${t}</button>`).join('');c.innerHTML=`<h2 class='text-3xl font-bold mb-6'>⏰ Recordatorios</h2><div class='card border-blue-300'><button onclick='document.getElementById("nuevo-rem").classList.toggle("hidden")' class='w-full bg-blue-600 text-white text-3xl font-bold py-6 rounded-2xl border-b-4 border-blue-800'>➕ Nuevo recordatorio</button><div id='nuevo-rem' class='hidden mt-4'><label class='etiqueta'>Perro / Cliente</label><select id='rem-dog' class='input-grande'>${opts}</select><label class='etiqueta'>Fecha</label><input id='rem-date' type='date' class='input-grande' value='${fechaBase}'><label class='etiqueta'>Hora</label><input id='rem-time' type='time' class='input-grande' value='${horaBase}'><label class='etiqueta'>Plantilla sugerida</label><select id='rem-template' class='input-grande' onchange='sugerirMensajeRecordatorio()'><option value=''>Elegir plantilla...</option>${REMINDER_TEMPLATES.map(t=>`<option>${t}</option>`).join('')}</select><div class='grid grid-cols-1 gap-3 mb-4'>${quickButtons}</div><label class='etiqueta'>Mensaje editable</label><textarea id='rem-message' class='input-grande h-28'></textarea><button onclick='guardarRecordatorio()' class='w-full bg-green-600 text-white text-3xl font-bold py-6 rounded-2xl border-b-4 border-green-800'>💾 Guardar recordatorio</button></div></div><h3 class='text-2xl font-bold mt-6 mb-3'>Pendientes</h3>${lista}`;}
function renderAgendaInicio(){const prox=[...appData.registros].sort((a,b)=>new Date(a.fecha)-new Date(b.fecha)).filter(r=>new Date(r.fecha)>=new Date()).slice(0,5);const items=prox.length?prox.map(r=>{const p=appData.perros.find(x=>x.id===r.perroId);return `<li class='py-2 border-b'><b>${new Date(r.fecha).toLocaleDateString('es-AR')}</b> - ${p?.nombre||'Perro'} (${r.servicio})</li>`}).join(''):'<li>No hay próximos paseos cargados.</li>';return `<div class='card border-indigo-200 bg-indigo-50 mt-4'><h3 class='text-2xl font-black text-indigo-800 mb-2'>📅 Próximos paseos</h3><ul class='text-lg mb-3'>${items}</ul><label class='etiqueta'>Calendario de actividad</label><input type='date' id='cal-fecha' class='input-grande' onchange='verActividadFecha(this.value)'><div id='cal-actividad' class='text-lg text-indigo-900'>Elegí una fecha para ver paseos/guarderías.</div></div>`;}
function verActividadFecha(fecha){const box=document.getElementById('cal-actividad');if(!box)return;const act=appData.registros.filter(r=>new Date(r.fecha).toISOString().slice(0,10)===fecha);box.innerHTML=act.length?act.map(r=>{const p=appData.perros.find(x=>x.id===r.perroId);return `<div>• ${r.servicio} - ${p?.nombre||'Perro'} ($${r.total})</div>`;actualizarMiniaturaRaza();}).join(''):'Sin actividad para esa fecha.';}
function renderPerfil(c){c.innerHTML=`<button onclick="navegar('inicio')" class='text-blue-600 text-2xl font-bold mb-6 flex items-center gap-2'><span>⬅</span> Volver a Inicio</button><h2 class='text-3xl font-bold mb-6'>Mi Perfil</h2><div class='card'><label class='etiqueta'>Usuario:</label><input id='pf-username' class='input-grande' value='${currentUser?.username||''}'><label class='etiqueta'>Contraseña actual (opcional):</label><input id='pf-current' type='password' class='input-grande'><label class='etiqueta'>Nueva contraseña (opcional):</label><input id='pf-new' type='password' class='input-grande'><label class='etiqueta'>Confirmar nueva contraseña:</label><input id='pf-confirm' type='password' class='input-grande'><button onclick='guardarPerfil()' class='w-full bg-green-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-green-800 mt-2'>💾 Guardar</button><button onclick='cerrarSesion()' class='w-full bg-red-100 text-red-700 text-xl font-bold py-4 rounded-xl border-2 border-red-300 mt-4'>Cerrar sesión</button></div>`;actualizarMiniaturaRaza();}
async function guardarPerfil(){try{await api('profile.update',{username:document.getElementById('pf-username').value,current_password:document.getElementById('pf-current').value,new_password:document.getElementById('pf-new').value,confirm_password:document.getElementById('pf-confirm').value});const p=await api('profile.get');currentUser=p.user;mostrarMensaje('Guardado con éxito.')}catch(e){mostrarMensaje(e.message,true)}}
function getBreedInfo(raza){return RAZAS_POPULARES.find(r=>r.name===raza)||RAZAS_POPULARES[RAZAS_POPULARES.length-1];}
function breedThumb(raza,w=64,h=64,foto=''){const b=getBreedInfo(raza);const src=foto||b.img;return `<img src='${src}' alt='${b.name}' class='rounded-xl object-cover border-2 border-gray-200' style='width:${w}px;height:${h}px' onerror="this.src='https://images.dog.ceo/breeds/mix/Max_D11.jpg'">`; }
function renderListaPerros(c){let h=`<div class='flex justify-between items-center mb-6'><h2 class='text-3xl font-bold'>Mis Perros</h2><button onclick="navegar('nuevo-perro')" class='bg-blue-600 text-white text-xl font-bold py-3 px-6 rounded-xl shadow border-b-4 border-blue-800'>+ Agregar</button></div>`;if(!appData.perros.length)h+=`<div class='card text-center text-2xl text-gray-500 py-10'>Todavía no hay perros anotados.</div>`;else appData.perros.forEach(p=>h+=`<div class='card flex justify-between items-center cursor-pointer' onclick="navegar('ficha-perro',${p.id})"><div class='flex items-center gap-4'>${breedThumb(p.raza,72,72,p.foto_url||'')}<div><h3 class='text-3xl font-bold text-gray-800'>${p.nombre}</h3><p class='text-xl text-gray-500'>De: ${p.dueno}</p><p class='text-sm text-gray-600'>Raza: ${p.raza||'Otro'} ${p.raza_otra?`(${p.raza_otra})`:''}</p></div></div><span class='text-3xl text-blue-600 font-bold'>VER ></span></div>`);c.innerHTML=h}
function renderFormularioPerro(c){c.innerHTML=`<button onclick="navegar('perros')" class='text-blue-600 text-2xl font-bold mb-6 flex items-center gap-2'><span>⬅</span> Volver atrás</button><h2 class='text-3xl font-bold mb-6'>Anotar un Nuevo Perro</h2><div class='card'><label class='etiqueta'>Nombre del perro:</label><input id='p-nombre' class='input-grande'><label class='etiqueta'>Raza (chicos y medianos populares):</label><select id='p-raza' class='input-grande' onchange='actualizarMiniaturaRaza()'>${RAZAS_POPULARES.map(r=>`<option value='${r.name}'>${r.name} (${r.size})</option>`).join('')}</select><div id='raza-otro-box' class='hidden'><label class='etiqueta'>Especificar otra raza:</label><input id='p-raza-otra' class='input-grande'></div><div class='mb-4'><label class='etiqueta'>Foto del perro (URL):</label><input id='p-foto-url' class='input-grande' placeholder='https://...'><div id='raza-thumb'></div></div><h3 class='text-2xl font-bold text-gray-800 mt-2 mb-3'>Dueños (prioridad de contacto)</h3><label class='etiqueta'>Nombre del dueño/a principal:</label><input id='p-dueno' class='input-grande'><label class='etiqueta'>Teléfono principal:</label><input id='p-tel' class='input-grande'><label class='etiqueta'>Nombre/teléfono alternativo:</label><input id='p-tel-alt' class='input-grande' placeholder='Ej: Mamá de Bruno - 11...'><label class='etiqueta'>Prioridad:</label><select id='p-prioridad' class='input-grande'><option>Primero dueño/a</option><option>Primero contacto alternativo</option><option>Cualquiera de los dos</option></select><h3 class='text-2xl font-bold text-gray-800 mt-2 mb-3'>Precios</h3><label class='etiqueta'>Precio por hora:</label><input id='p-precio-hora' class='input-grande' placeholder='Ej: 9000'><label class='etiqueta'>Combos:</label><input id='p-precio-combos' class='input-grande' placeholder='Ej: 10 horas = $80.000'><label class='etiqueta'>Pack mensual:</label><input id='p-precio-mensual' class='input-grande' placeholder='Ej: 20% descuento'><label class='etiqueta'>Personalizado:</label><textarea id='p-precio-personalizado' class='input-grande h-24' placeholder='Cualquier acuerdo especial'></textarea><label class='etiqueta'>¿Tiene las vacunas al día?</label><select id='p-vacunas' class='input-grande'><option>Sí, todo al día</option><option>Faltan vacunas</option><option>No estoy seguro</option></select><label class='etiqueta'>Notas de Salud / Comportamiento:</label><textarea id='p-salud' class='input-grande h-32'></textarea><label class='etiqueta'>Alimentación / Comida:</label><textarea id='p-comida' class='input-grande h-32'></textarea><button onclick='guardarPerro()' class='w-full bg-green-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-green-800 mt-4'>💾 Guardar Ficha</button></div>`;actualizarMiniaturaRaza();}
function actualizarMiniaturaRaza(){const sel=document.getElementById('p-raza');const box=document.getElementById('raza-thumb');const otro=document.getElementById('raza-otro-box');if(!sel||!box)return;const b=getBreedInfo(sel.value);const foto=document.getElementById('p-foto-url')?.value||'';box.innerHTML=breedThumb(sel.value,120,120,foto)+`<p class='text-sm text-gray-600 mt-2'>${b.name}</p>`;if(otro)otro.classList.toggle('hidden',sel.value!=='Otro');}
async function guardarPerro(){try{await api('dogs.create',{nombre:document.getElementById('p-nombre').value,dueno:document.getElementById('p-dueno').value,telefono:document.getElementById('p-tel').value,telefono_alt:document.getElementById('p-tel-alt').value,prioridad_contacto:document.getElementById('p-prioridad').value,precio_hora:document.getElementById('p-precio-hora').value,precio_combos:document.getElementById('p-precio-combos').value,precio_mensual:document.getElementById('p-precio-mensual').value,precio_personalizado:document.getElementById('p-precio-personalizado').value,raza:document.getElementById('p-raza').value,raza_otra:document.getElementById('p-raza-otra')?.value||'',foto_url:document.getElementById('p-foto-url')?.value||'',vacunas:document.getElementById('p-vacunas').value,salud:document.getElementById('p-salud').value,comida:document.getElementById('p-comida').value});await cargarDatos();mostrarMensaje('¡Perro guardado con éxito!');navegar('perros')}catch(e){mostrarMensaje(e.message,true)}}
function renderFichaPerro(c,id){const p=appData.perros.find(x=>+x.id===+id);if(!p)return navegar('perros');const h=appData.registros.filter(r=>r.perroId==id);const pr=JSON.parse(p.precios_json||'{}');const z=[...new Set(h.filter(r=>r.servicio!=='Guardería').map(r=>r.zona))].join(', ')||'Sin zonas de paseo aún';c.innerHTML=`<button onclick="navegar('perros')" class='text-blue-600 text-2xl font-bold mb-4 flex items-center gap-2'><span>⬅</span> Volver a la lista</button><div class='card border-4 border-blue-600'><div class='flex items-center gap-4 mb-6'>${breedThumb(p.raza,110,110,p.foto_url||'')}<div><h2 class='text-4xl font-black text-gray-800'>${p.nombre}</h2><p class='text-lg text-gray-600'>Raza: ${p.raza||'Otro'} ${p.raza_otra?`(${p.raza_otra})`:''}</p></div></div><div class='bg-yellow-50 p-4 rounded-xl mb-4 border-2 border-yellow-300'><span class='etiqueta text-yellow-800'>👨‍👩‍👧 Dueños</span><p class='text-xl text-gray-800'><b>Prioridad:</b> ${p.prioridad_contacto||'Primero dueño/a'}</p><p class='text-xl text-gray-800'><b>Principal:</b> ${p.dueno}</p><p class='text-lg text-blue-700 font-bold'>📞 ${p.telefono||'Sin teléfono'}</p><p class='text-xl text-gray-800 mt-2'><b>Alternativo:</b> ${p.telefono_alt||'No informado'}</p></div><div class='bg-green-50 p-4 rounded-xl mb-4 border-2 border-green-300'><span class='etiqueta text-green-800'>💵 Precios</span><p class='text-lg'><b>Hora:</b> ${pr.hora||'No definido'}</p><p class='text-lg'><b>Combos:</b> ${pr.combos||'No definido'}</p><p class='text-lg'><b>Pack mensual:</b> ${pr.mensual||'No definido'}</p><p class='text-lg'><b>Personalizado:</b> ${pr.personalizado||'No definido'}</p></div><div class='bg-blue-50 p-4 rounded-xl mb-6 border border-blue-200'><span class='etiqueta text-blue-800'>🚶‍♂️ Historial de Trabajos:</span><p class='text-xl text-gray-800'>Lo sacaste <b>${h.length} veces</b>.</p><p class='text-lg text-gray-600 mt-2'>Zonas de paseo: ${z}</p></div><button onclick='editarPerro(${p.id})' class='w-full bg-blue-100 text-blue-700 text-xl font-bold py-4 rounded-xl border-2 border-blue-300 mb-3'>Editar ficha</button><button onclick='eliminarPerro(${p.id})' class='w-full bg-red-100 text-red-700 text-xl font-bold py-4 rounded-xl border-2 border-red-300'>Borrar esta ficha</button></div>`;actualizarMiniaturaRaza();}
async function eliminarPerro(id){if(!confirm('¿Seguro que desea borrar esta ficha?'))return;try{await api('dogs.delete',{id});await cargarDatos();mostrarMensaje('Ficha borrada');navegar('perros')}catch(e){mostrarMensaje(e.message,true)}}
function renderAnotarPaseo(c){if(!appData.perros.length){c.innerHTML=`<h2 class='text-3xl font-bold mb-6'>Anotar un Trabajo</h2><div class='card text-center'><p class='text-2xl mb-4'>Primero tenés que anotar un perro en el sistema.</p><button onclick="navegar('nuevo-perro')" class='bg-blue-600 text-white text-2xl font-bold py-4 px-6 rounded-xl w-full'>Ir a crear perro</button></div>`;return;}const chips=appData.perros.map(p=>`<button type='button' onclick='togglePerro(${p.id})' data-dog='${p.id}' class='reg-chip border-2 border-blue-200 bg-blue-50 text-blue-800 text-xl font-bold p-3 rounded-2xl flex items-center gap-2'>${breedThumb(p.raza,46,46)}<span>${p.nombre}</span></button>`).join('');const dias=['Lunes','Martes','Miércoles','Jueves','Viernes','Sábado','Domingo'].map((d,i)=>`<button type='button' onclick='toggleDia(${i})' data-dia='${i}' class='dia-chip border-2 border-gray-300 bg-white text-sm font-bold px-2 py-2 rounded-xl'>${d}</button>`).join('');c.innerHTML=`<h2 class='text-3xl font-bold mb-6'>📝 Anotar Trabajo Terminado</h2><div class='card'><label class='etiqueta'>¿Qué perro(s) incluís?</label><div class='grid grid-cols-2 gap-3 mb-6'>${chips}</div><label class='etiqueta'>¿Qué trabajo fue?</label><div class='flex gap-4 mb-6'><label class='flex-1 text-center p-4 rounded-xl border-2 cursor-pointer text-2xl border-blue-500 bg-blue-100 font-bold text-blue-700' id='lbl-paseo'><input type='radio' name='reg-servicio' value='Paseo' checked class='hidden' onchange='seleccionarServicio()'>🚶‍♂️ Paseo</label><label class='flex-1 text-center p-4 rounded-xl border-2 cursor-pointer text-2xl border-gray-300 bg-gray-100 text-gray-600' id='lbl-guarderia'><input type='radio' name='reg-servicio' value='Guardería' class='hidden' onchange='seleccionarServicio()'>🏠 Guardería</label></div><div id='bloque-zona'><label class='etiqueta'>¿Por dónde? (Zona de Devoto)</label><select id='reg-zona' class='input-grande'><option>Plaza Arenales</option><option>Plaza Ricchieri</option><option>Devoto R (Calles)</option><option>Estación Devoto</option></select></div><label class='etiqueta'>Tipo de cobro:</label><input type='hidden' id='reg-pago' value='Paseo suelto (normal)'><div class='grid grid-cols-1 gap-2 mb-4'><button type='button' onclick="seleccionarTipoPago('Paseo suelto (normal)')" id='pago-paseo' class='tipo-pago-btn border-2 border-blue-500 bg-blue-100 text-blue-800 text-xl font-bold p-3 rounded-xl'>Paseo suelto (normal)</button><button type='button' onclick="seleccionarTipoPago('Abono mensual')" id='pago-mensual' class='tipo-pago-btn border-2 border-gray-300 bg-white text-gray-700 text-xl font-bold p-3 rounded-xl'>Abono mensual</button><button type='button' onclick="seleccionarTipoPago('Guardería por día')" id='pago-guarderia-dia' class='tipo-pago-btn border-2 border-gray-300 bg-white text-gray-700 text-xl font-bold p-3 rounded-xl'>Guardería por día</button><button type='button' onclick="seleccionarTipoPago('Guardería + comida')" id='pago-guarderia-comida' class='tipo-pago-btn border-2 border-gray-300 bg-white text-gray-700 text-xl font-bold p-3 rounded-xl'>Guardería + comida</button></div><div id='mensual-box' class='bg-blue-50 border-2 border-blue-200 p-4 rounded-xl mb-4 hidden'><label class='etiqueta'>Precio por hora personalizado (abono mensual)</label><input type='number' id='reg-tarifa-mensual' value='9000' min='1' class='input-grande' onchange='calcularTotal()'><label class='etiqueta'>Horas por día</label><input type='number' id='reg-horas-dia' value='2' min='1' class='input-grande' onchange='calcularTotal()'><label class='etiqueta'>Días semanales</label><div class='grid grid-cols-2 gap-2 mb-4'>${dias}</div><label class='etiqueta'>Semanas del mes (factor mensual)</label><input type='number' id='reg-semanas' value='${FACTOR_MENSUAL_DEFAULT}' min='1' max='6' class='input-grande' onchange='calcularTotal()'></div><label id='label-horas' class='etiqueta'>¿Cuántas horas fueron?</label><input type='number' id='reg-horas' value='1' min='1' class='input-grande' onchange='calcularTotal()'><label class='etiqueta'>¿Cuántos días?</label><input type='number' id='reg-dias' value='1' min='1' class='input-grande' onchange='calcularTotal()'><div class='bg-green-100 border-2 border-green-400 p-4 rounded-xl text-center mb-4'><span class='text-xl text-green-800 font-bold block mb-1'>Sugerencia automática:</span><span id='reg-total' class='text-5xl font-black text-green-700'>$9000</span></div><div id='reg-resumen' class='bg-yellow-100 border-4 border-yellow-400 p-5 rounded-2xl text-center mb-4 text-2xl font-bold text-yellow-900'></div><label class='etiqueta'>Precio final a cobrar:</label><input type='number' id='reg-total-manual' min='0.01' step='0.01' class='input-grande text-4xl font-black text-green-700' onchange='actualizarPrecioManual()'><p id='reg-manual-msg' class='hidden text-2xl font-bold text-orange-700 bg-orange-100 border-2 border-orange-300 rounded-xl p-3 mb-6'>Se usará precio manual</p><button onclick='guardarRegistro()' class='w-full bg-blue-600 text-white text-3xl font-bold py-6 rounded-2xl shadow-lg border-b-4 border-blue-800'>✅ Guardar y Cobrar</button></div>`;seleccionarServicio();seleccionarTipoPago('Paseo suelto (normal)');calcularTotal();const m=document.getElementById('reg-total-manual');if(m){m.addEventListener('input',()=>{m.dataset.editado='1';actualizarPrecioManual();});}}
function togglePerro(id){const b=document.querySelector(`[data-dog="${id}"]`);if(!b)return;b.classList.toggle('bg-blue-700');b.classList.toggle('text-white');b.classList.toggle('border-blue-700');calcularTotal();}
function toggleDia(i){const b=document.querySelector(`[data-dia="${i}"]`);if(!b)return;b.classList.toggle('bg-indigo-700');b.classList.toggle('text-white');b.classList.toggle('border-indigo-700');calcularTotal();}
function getPerrosSeleccionados(){return [...document.querySelectorAll('.reg-chip.bg-blue-700')].map(x=>parseInt(x.dataset.dog)).filter(Boolean);}
function getDiasSeleccionados(){const n=['Lunes','Martes','Miércoles','Jueves','Viernes','Sábado','Domingo'];return [...document.querySelectorAll('.dia-chip.bg-indigo-700')].map(x=>n[parseInt(x.dataset.dia)]);}
function seleccionarServicio(){const s=document.querySelector('input[name="reg-servicio"]:checked')?.value||'Paseo';const lp=document.getElementById('lbl-paseo'),lg=document.getElementById('lbl-guarderia'),bz=document.getElementById('bloque-zona');lp.className=`flex-1 text-center p-4 rounded-xl border-2 cursor-pointer text-2xl ${s==='Paseo'?'border-blue-500 bg-blue-100 font-bold text-blue-700':'border-gray-300 bg-gray-100 text-gray-600'}`;lg.className=`flex-1 text-center p-4 rounded-xl border-2 cursor-pointer text-2xl ${s==='Guardería'?'border-blue-500 bg-blue-100 font-bold text-blue-700':'border-gray-300 bg-gray-100 text-gray-600'}`;if(bz)bz.style.display=s==='Guardería'?'none':'block';}
function seleccionarTipoPago(tipo){const input=document.getElementById('reg-pago');if(!input)return;input.value=tipo;const map=[['pago-paseo','Paseo suelto (normal)'],['pago-mensual','Abono mensual'],['pago-guarderia-dia','Guardería por día'],['pago-guarderia-comida','Guardería + comida']];map.forEach(([id,val])=>{const b=document.getElementById(id);if(!b)return;const on=val===tipo;b.className=`tipo-pago-btn border-2 text-xl font-bold p-3 rounded-xl ${on?'border-blue-500 bg-blue-100 text-blue-800':'border-gray-300 bg-white text-gray-700'}`;});calcularTotal();}
function calcularTotal(){const perros=getPerrosSeleccionados();const cantidadPerros=Math.max(1,perros.length);const tp=document.getElementById('reg-pago').value;document.getElementById('mensual-box').classList.toggle('hidden',tp!=='Abono mensual');document.getElementById('label-horas').style.display=tp==='Mensual'?'none':'block';document.getElementById('reg-horas').style.display=tp==='Mensual'?'none':'block';let t=0,horas=1,dias=[],factor=1,base=0;if(tp==='Abono mensual'){horas=parseInt(document.getElementById('reg-horas-dia').value)||2;dias=getDiasSeleccionados();factor=parseInt(document.getElementById('reg-semanas').value)||FACTOR_MENSUAL_DEFAULT;const tarifaMensual=parseFloat(document.getElementById('reg-tarifa-mensual')?.value||TARIFA_HORA)||TARIFA_HORA;base=tarifaMensual*horas*Math.max(1,dias.length)*factor;t=base-(base*DESCUENTO_MENSUAL);}else{horas=parseInt(document.getElementById('reg-horas').value)||1;base=horas*TARIFA_HORA;t=base;}if(cantidadPerros>1){t=COMBO_MULTIPERRO?(t*(1-DESCUENTO_COMBO)):(t*cantidadPerros);}const total=Math.round(t*100)/100;document.getElementById('reg-total').innerText='$'+total;const resumen=document.getElementById('reg-resumen');const perrosTxt=getPerrosSeleccionados().map(id=>(appData.perros.find(p=>p.id===id)||{}).nombre).join(', ')||'Sin selección';resumen.innerHTML=`🐶 Perros: ${perrosTxt}<br>📅 Días: ${dias.join(', ')||'N/A'}<br>⏱️ Horas/día: ${tp==='Mensual'?horas:'N/A'}<br>💵 Total final: $${total}`;const manual=document.getElementById('reg-total-manual');if(manual && !manual.dataset.editado){manual.value=total.toFixed(2);}actualizarPrecioManual();return total}
function actualizarPrecioManual(){const manual=document.getElementById('reg-total-manual');const sugerido=calcularSugeridoSolo();const msg=document.getElementById('reg-manual-msg');if(!manual||!msg)return;const v=parseFloat(manual.value);const valido=Number.isFinite(v)&&v>0;manual.classList.toggle('border-red-500',manual.value!==''&&!valido);const usaManual=valido&&Math.abs(v-sugerido)>0.009;msg.classList.toggle('hidden',!usaManual);}
function calcularSugeridoSolo(){const h=parseInt(document.getElementById('reg-horas').value)||1;const tp=document.getElementById('reg-pago').value;let t=h*TARIFA_HORA;if(tp==='Abono mensual'){const tarifaMensual=parseFloat(document.getElementById('reg-tarifa-mensual')?.value||TARIFA_HORA)||TARIFA_HORA;t=h*tarifaMensual;t-=t*DESCUENTO_MENSUAL;}return Math.round(t*100)/100}
async function guardarRegistro(){try{const perros=getPerrosSeleccionados();if(!perros.length){mostrarMensaje('Seleccioná al menos un perro.',true);return;}const tipoPago=document.getElementById('reg-pago').value;const servicio=document.querySelector('input[name="reg-servicio"]:checked').value;const totalManual=parseFloat(document.getElementById('reg-total-manual').value);if(!Number.isFinite(totalManual)||totalManual<=0){mostrarMensaje('El precio final debe ser un número positivo.',true);return;}const dias=getDiasSeleccionados();const horasMensual=parseInt(document.getElementById('reg-horas-dia')?.value||2);const diasCantidad=parseInt(document.getElementById('reg-dias')?.value||1);const semanas=parseInt(document.getElementById('reg-semanas')?.value||FACTOR_MENSUAL_DEFAULT);await api('jobs.create',{dog_id:perros[0],dog_ids:perros,servicio,zona:servicio==='Guardería'?'No aplica':document.getElementById('reg-zona').value,horas:tipoPago==='Abono mensual'?horasMensual:(parseInt(document.getElementById('reg-horas').value)||1),dias:diasCantidad,tipo_pago:tipoPago,tarifa_unitaria:tipoPago==='Abono mensual'?(parseFloat(document.getElementById('reg-tarifa-mensual')?.value||TARIFA_HORA)||TARIFA_HORA):TARIFA_HORA,descuento_pct:tipoPago==='Abono mensual'?DESCUENTO_MENSUAL:0,total:totalManual,detalle:{modo_multi_perro:COMBO_MULTIPERRO?'combo':'por_perro',descuento_combo:COMBO_MULTIPERRO?DESCUENTO_COMBO:0,horas_por_dia:tipoPago==='Abono mensual'?horasMensual:null,dias_semana:tipoPago==='Abono mensual'?dias:[],factor_mensual:tipoPago==='Abono mensual'?semanas:1,tarifa_hora:tipoPago==='Abono mensual'?(parseFloat(document.getElementById('reg-tarifa-mensual')?.value||TARIFA_HORA)||TARIFA_HORA):TARIFA_HORA}});await cargarDatos();mostrarMensaje('¡Trabajo guardado!');navegar('inicio')}catch(e){mostrarMensaje(e.message,true)}}
function renderCuentas(c){const m=new Date().getMonth(),a=new Date().getFullYear();const tm=appData.registros.filter(r=>{const d=new Date(r.fecha);return d.getMonth()===m&&d.getFullYear()===a});const cobrados=tm.filter(r=>r.estadoCobro==='cobrado');const pendientes=tm.filter(r=>r.estadoCobro!=='cobrado');const g=cobrados.reduce((x,y)=>x+y.total,0);const aCobrar=pendientes.reduce((x,y)=>x+y.total,0);const ul=[...appData.registros].reverse().slice(0,10);let l=ul.length?ul.map(t=>`<div class='flex justify-between items-center border-b border-gray-200 py-4'><div><p class='text-xl font-bold text-gray-800'>${t.servicio} - ${(appData.perros.find(p=>p.id==t.perroId)||{}).nombre||'Perro borrado'}</p><p class='text-lg text-gray-500'>🗓️ ${new Date(t.fecha).toLocaleDateString('es-AR',{day:'2-digit',month:'2-digit'})} | ⏱️ ${t.horas} hora(s)</p></div><div class='text-2xl font-black text-green-600'>${t.estadoCobro==='cobrado'?'+':'⏳'}$${t.total}</div>${t.estadoCobro==='cobrado'?'':`<button onclick='marcarCobrado(${t.id})' class='ml-3 bg-green-600 text-white px-3 py-2 rounded-lg font-bold'>Marcar cobrado</button>`}</div>`).join(''):`<p class='text-xl text-gray-500 text-center py-6'>Todavía no hay trabajos cobrados.</p>`;c.innerHTML=`<h2 class='text-3xl font-bold mb-6'>💰 Mis Cuentas</h2><div class='card bg-green-600 text-white text-center shadow-xl border-none'><p class='text-2xl mb-2 text-green-100 font-semibold'>Plata ganada este mes</p><p class='text-6xl font-black mb-2'>$${g}</p><p class='text-lg text-green-200'>A cobrar: $${aCobrar}</p></div><h3 class='text-2xl font-bold mb-4 mt-8 text-gray-700'>Últimos trabajos cobrados:</h3><div class='card'>${l}</div>`;actualizarMiniaturaRaza();}
function editarPerro(id){const p=appData.perros.find(x=>+x.id===+id);if(!p)return;const n=prompt('Nombre del perro',p.nombre);if(!n)return;const d=prompt('Dueño/a',p.dueno)||p.dueno;api('dogs.update',{id:p.id,nombre:n,dueno:d,telefono:p.telefono,telefono_alt:p.telefono_alt,prioridad_contacto:p.prioridad_contacto,vacunas:p.vacunas,salud:p.salud,comida:p.comida,precio_hora:(JSON.parse(p.precios_json||'{}').hora||''),precio_combos:(JSON.parse(p.precios_json||'{}').combos||''),precio_mensual:(JSON.parse(p.precios_json||'{}').mensual||''),precio_personalizado:(JSON.parse(p.precios_json||'{}').personalizado||''),raza:p.raza||'Otro',raza_otra:p.raza_otra||'',foto_url:p.foto_url||''}).then(async()=>{await cargarDatos();mostrarMensaje('Ficha actualizada');navegar('ficha-perro',id)}).catch(e=>mostrarMensaje(e.message,true));}
async function marcarCobrado(id){try{await api('jobs.pay',{id});await cargarDatos();navegar('cuentas');mostrarMensaje('Marcado como cobrado');}catch(e){mostrarMensaje(e.message,true)}}
window.onload=async()=>{const app=document.getElementById('app-content');if(NEEDS_BOOTSTRAP){renderBootstrap(app);return;}try{const p=await api('profile.get');currentUser=p.user;setNav(true);await cargarDatos();navegar('inicio')}catch(e){renderLogin(app);}}
</script></body></html>
